```typescript
enum Color {
  Red = 1,
  Green = 2,
  Blue = 3
}

enum Size {
  Small,
  Medium,
  Large
}

function enumValues<T>(enumType: T) {
  return Object.keys(enumType).filter(key => isNaN(Number(key)));
}

console.log(enumValues(Color)); // ['Red', 'Green', 'Blue']
console.log(enumValues(Size)); // ['Small', 'Medium', 'Large']
```
